class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        def backtrack(start, path):
            if start == len(num):
                if len(path) >= 3:
                    return path
                return []
            for end in range(start + 1, len(num) + 1):
                curr = num[start:end]
                if len(curr) > 1 and curr[0] == '0':
                    return []
                if int(curr) > 2**31 - 1:
                    return []
                if len(path) < 2 or path[-1] + path[-2] == int(curr):
                    result = backtrack(end, path + [int(curr)])
                    if result:
                        return result
            return []

        return backtrack(0, [])

